```js
async function fetchUser(id, retries = 2) {
  try {
    const res = await fetch(`/api/users/${id}`);
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    const data = await res.json();
    return { name: data.name, email: data.email };
  } catch (err) {
    if (retries > 0) return fetchUser(id, retries - 1);
    console.error('fetchUser failed after retries:', err.message);
    return null;
  }
}
```
The logic is identical to the Promise version — same retry countdown, same null fallback — but `async/await` with a single `try/catch` replaces the `.then()/.catch()` chain, making the control flow easier to read and the error boundary explicit.
